"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[9778],{3500(e,o,t){t.r(o),t.d(o,{assets:()=>r,contentTitle:()=>h,default:()=>u,frontMatter:()=>i,metadata:()=>n,toc:()=>d});const n=JSON.parse('{"id":"stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-13","title":"Discourses \u2014 Book 2, Chapter 13","description":"Book 2 \u2014 Chapter 13","source":"@site/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-13.md","sourceDirName":"stoicism/epictetus/discourses/book-2","slug":"/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-13","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-13","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":14,"frontMatter":{"sidebar_position":14,"title":"Discourses \u2014 Book 2, Chapter 13","sidebar_label":"Book 2, Ch. 13"},"sidebar":"philosophersSidebar","previous":{"title":"Book 2, Ch. 12","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-12"},"next":{"title":"Book 2, Ch. 14","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-14"}}');var s=t(4848),a=t(8453);const i={sidebar_position:14,title:"Discourses \u2014 Book 2, Chapter 13",sidebar_label:"Book 2, Ch. 13"},h="Discourses",r={},d=[{value:"Book 2 \u2014 Chapter 13",id:"book-2--chapter-13",level:2},{value:"Concerning Anxiety",id:"concerning-anxiety",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function l(e){const o={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,a.R)(),...e.components},{Details:t}=o;return t||function(e,o){throw new Error("Expected "+(o?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,s.jsxs)(s.Fragment,{children:[(0,s.jsxs)("div",{style:{textAlign:"center"},children:[(0,s.jsx)(o.header,{children:(0,s.jsx)(o.h1,{id:"discourses",children:"Discourses"})}),(0,s.jsx)(o.h2,{id:"book-2--chapter-13",children:"Book 2 \u2014 Chapter 13"}),(0,s.jsx)(o.h3,{id:"concerning-anxiety",children:"Concerning Anxiety"})]}),"\n",(0,s.jsx)(o.p,{children:(0,s.jsx)(o.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,s.jsxs)(t,{open:!0,children:[(0,s.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,s.jsx)(o.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,s.jsx)(o.p,{children:"Anxiety is a diagnostic. When you see someone anxious, you know immediately that they want something outside their control. The musician playing alone feels no anxiety \u2014 he knows what he's doing. On stage, wanting applause as well as good performance, he trembles; the second want is outside his mastery."}),(0,s.jsx)(o.p,{children:"The anxiety principle is fully general: wherever you have knowledge and have confined your desires to what you can control, you have confidence. Wherever you haven't, you're exposed. Zeno going to meet Antigonus felt nothing \u2014 Antigonus controlled nothing Zeno valued. Antigonus going to meet Zeno was anxious \u2014 he wanted to please Zeno, and that lay beyond his control."}),(0,s.jsx)(o.p,{children:"The chapter ends harshly: if you're genuinely afraid of the man with power over your body, at least be honest about it. Stop calling yourself a philosopher. You have given them the hold they have over you by valuing what they can take. Socrates and Diogenes spoke as they did because they had actually trained themselves to that; you haven't."})]}),"\n",(0,s.jsxs)(t,{open:!0,children:[(0,s.jsx)("summary",{children:"Text"}),(0,s.jsx)(o.h2,{id:"text",children:"Text"}),(0,s.jsx)(o.p,{children:"WHEN I see a man in a state of anxiety, I say, 'What can this man want? If he did not want something which is not in his power, how could he still be anxious? It is for this reason that one who sings to the lyre is not anxious when he is performing by himself, but when he enters the theatre, even if he has a very good voice and plays well: for he not only wants to perform well, but also to win a great name, and that is beyond his own control."}),(0,s.jsx)(o.p,{children:"In fact, where he has knowledge there he has confidence. Bring in any unskilled person you like, and he pays no heed to him. On the other hand he is anxious whenever he has no knowledge and has made no study of the subject. What does this mean? He does not know what 'the people' is, nor what its praise is worth: he has learnt to strike the bottom note or the top note, but he does not know what the praise of the multitude is, nor what value it has in life; he has made no study of that. So he is bound to tremble and grow pale."}),(0,s.jsx)(o.p,{children:"When I see a man, then, in this state of fear I cannot say that he is no performer with the lyre, but I can say something else of him, and not one thing but many. And first of all I call him a stranger and say, This man does not know where in the world he is; though he has been with us so long, he does not know the laws and customs of the City--what he may do and what he may not do--no, nor has he called in a lawyer at any time to tell him and explain to him what are the requirements of the law. Of course he does not draw up a will without knowing how he ought to draw it up, or without calling in one who knows, nor does he lightly put his seal to a guarantee or give a written security; but he calls in no lawyer when he is exercising the will to"}),(0,s.jsx)(o.p,{children:"get and will to avoid, impulse and intention and purpose. What do I mean by 'having no lawyer'? I mean that he does not know that he is wishing to have what is not given him, and wishing not to have what he cannot avoid, and he does not know what is his own and what is not his own. If he did know, he would never feel hindrance or constraint or anxiety; how could he? Does any one fear about things which are not evil?"}),(0,s.jsx)(o.p,{children:"'No.'"}),(0,s.jsx)(o.p,{children:"Or again about things which are evil but are in his power to prevent? 'Certainly not.'"}),(0,s.jsx)(o.p,{children:"If, then, nothing beyond our will's control is either good or evil, and everything within our will's control depends entirely on ourselves, so that no one can take any such thing away from us or win it for us against our will, what room is left for anxiety? Yet we are anxious for our bit of a body, for our bit of property, for what Caesar will think, but are not anxious at all for what is within us. Am I anxious about not conceiving a false thought? No, for that depends on myself."}),(0,s.jsx)(o.p,{children:"Or about indulging an impulse contrary to nature?"}),(0,s.jsx)(o.p,{children:"No, not about this either. So, when you see a man pale, just as the physician, judging from his colour, says, 'This man's spleen is out of order, or that man's liver', so do you say, 'This man is disordered in the will to get and the will to avoid, he is not in the right way, he is feverish'; for nothing else changes the complexion and causes a man to tremble and his teeth to chatter,"}),(0,s.jsx)(o.p,{children:"and droop the knee and sink upon his feet."}),(0,s.jsx)(o.p,{children:"[Homer, Iliad, XIII, 281]"}),(0,s.jsx)(o.p,{children:"[paragraph continues] Therefore Zeno was not distressed when he was going to meet Antigonus, for Antigonus had no authority over any of the things that Zeno admired, and Zeno paid no attention to the possessions of Antigonus. Antigonus was anxious when he was going to meet Zeno, and with good reason, for he wanted to please him, and this lay beyond his control; but Zeno did not wish to please Antigonus, any more than any artist cares to please one who has no skill."}),(0,s.jsx)(o.p,{children:"Do I want to please you? Why should I? Do you know the standards by which man judges man? Have you made it your study to learn what a good man is and what a bad man is, and what makes each of them so? Why, then, are you not good yourself?"}),(0,s.jsx)(o.p,{children:"'Not good? What do you mean?' he replies."}),(0,s.jsx)(o.p,{children:"Why, no good man whines or groans or laments, no good man grows pale or trembles or says, 'How will he receive me? What hearing will he give me?'"}),(0,s.jsx)(o.p,{children:"Slave, he will do as he thinks good. What concern have you in what does not belong to you? Is it not his fault if he gives a bad reception to what you offer?"}),(0,s.jsx)(o.p,{children:"'His fault, certainly.'"}),(0,s.jsx)(o.p,{children:"But can the fault be one man's and the harm another's?"}),(0,s.jsx)(o.p,{children:"'No.'"}),(0,s.jsx)(o.p,{children:"Why, then, are you anxious about another's concerns?"}),(0,s.jsx)(o.p,{children:"'Nay, but I am anxious to know how I am to address him.' What, is it not in your power to address him as you will? 'Yes, but I am afraid I may lose my self-possession.'"}),(0,s.jsx)(o.p,{children:"Are you afraid of losing your self-possession when you are going to write the name Dion?"}),(0,s.jsx)(o.p,{children:"'Certainly not.'"}),(0,s.jsx)(o.p,{children:"What is the reason? Is it not, that you have practised writing?"}),(0,s.jsx)(o.p,{children:"Of course it is. Or again, when you are about to read, would you not be in like case?"}),(0,s.jsx)(o.p,{children:"'Exactly.'"}),(0,s.jsx)(o.p,{children:"What is the reason? The reason is that every art contains within it an element of strength and confidence. Have you not practised speaking, then? What else did you study at school? You studied syllogisms and variable arguments. What for? Was it not that .you might converse with skill, and does not 'with skill' mean in good season, with security and good sense, and, more than that, without failure or hindrance, and, to crown all, with confidence?"}),(0,s.jsx)(o.p,{children:"'Yes.'"}),(0,s.jsx)(o.p,{children:"Well, if you are a rider and have to confront a man on foot in the plain, where you have the advantage of practice and he has not, are you anxious?"}),(0,s.jsx)(o.p,{children:"'Nay, but he has power to put me to death.'"}),(0,s.jsx)(o.p,{children:"Miserable man, tell the truth and be not a braggart nor claim to be a philosopher. Know who are your masters. As long as you give them this hold over your body, you must follow every one who is stronger than you."}),(0,s.jsx)(o.p,{children:"But Socrates, who spoke to the Tyrants, to his judges, and in prison, in the tone we know, had studied speaking to some purpose. So had Diogenes, who spoke in the same tone to Alexander, to Philip, to the pirates, to his purchaser. . . . Leave this to those who have made it their concern, to the confident: and do you go to your own concerns and never leave them again. Go and sit in your corner and weave syllogisms and propound them to others,"}),(0,s.jsx)(o.p,{children:"No ruler of a state is found in you."}),(0,s.jsx)(o.p,{children:"[Author unknown]"})]})]})}function u(e={}){const{wrapper:o}={...(0,a.R)(),...e.components};return o?(0,s.jsx)(o,{...e,children:(0,s.jsx)(l,{...e})}):l(e)}},8453(e,o,t){t.d(o,{R:()=>i,x:()=>h});var n=t(6540);const s={},a=n.createContext(s);function i(e){const o=n.useContext(a);return n.useMemo(function(){return"function"==typeof e?e(o):{...o,...e}},[o,e])}function h(e){let o;return o=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:i(e.components),n.createElement(a.Provider,{value:o},e.children)}}}]);